contracts/CLDToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Capped.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title CLDToken
 * @dev Cloudana DePIN token with capped supply and VRF-based mystery cap
 */
contract CLDToken is ERC20, ERC20Capped, AccessControl {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant CAP_SETTER_ROLE = keccak256("CAP_SETTER_ROLE");

    uint256 private _finalCap;
    bool private _capFinalized;

    event CapFinalized(uint256 finalCap);
    event CapSet(uint256 newCap);

    constructor(
        string memory name,
        string memory symbol,
        uint256 temporaryCap
    ) ERC20(name, symbol) ERC20Capped(temporaryCap) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(CAP_SETTER_ROLE, msg.sender);
        // Temporary cap is set via ERC20Capped constructor
        _finalCap = 0; // Unset initially
        _capFinalized = false;
    }

    /**
     * @dev Set the final cap (only by oracle with CAP_SETTER_ROLE)
     * @param newCap The final cap amount (must be <= current cap)
     */
    function setFinalCap(uint256 newCap) external onlyRole(CAP_SETTER_ROLE) {
        require(!_capFinalized, "CLDToken: Cap already finalized");
        require(newCap > 0, "CLDToken: Cap must be greater than zero");
        require(newCap <= cap(), "CLDToken: Final cap cannot exceed temporary cap");

        _finalCap = newCap;
        _capFinalized = true;

        emit CapFinalized(newCap);
    }

    /**
     * @dev Get the final cap
     */
    function finalCap() external view returns (uint256) {
        return _finalCap;
    }

    /**
     * @dev Check if cap is finalized
     */
    function capFinalized() external view returns (bool) {
        return _capFinalized;
    }

    /**
     * @dev Override cap() to return finalCap if finalized, otherwise temporary cap
     */
    function cap() public view override returns (uint256) {
        if (_capFinalized) {
            return _finalCap;
        }
        return super.cap();
    }

    /**
     * @dev Mint tokens (only by addresses with MINTER_ROLE)
     * @param to Address to mint to
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        require(totalSupply() + amount <= cap(), "CLDToken: Cap exceeded");
        _mint(to, amount);
    }

    /**
     * @dev Batch mint tokens to multiple addresses (gas optimized)
     * @param recipients Array of recipient addresses
     * @param amounts Array of amounts to mint (must match recipients length)
     */
    function batchMint(address[] calldata recipients, uint256[] calldata amounts) 
        external onlyRole(MINTER_ROLE) 
    {
        require(recipients.length == amounts.length, "CLDToken: Array length mismatch");

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < amounts.length; i++) {
            totalAmount += amounts[i];
        }

        require(totalSupply() + totalAmount <= cap(), "CLDToken: Cap exceeded");

        for (uint256 i = 0; i < recipients.length; i++) {
            _mint(recipients[i], amounts[i]);
        }
    }

    /**
     * @dev Override _update to enforce cap
     */
    function _update(address from, address to, uint256 value) internal override(ERC20, ERC20Capped) {
        super._update(from, to, value);
    }
}

contracts/Config.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title Config
 * @dev Configuration contract for Cloudana system parameters
 * Can be updated by governance in the future
 */
contract Config is AccessControl {
    bytes32 public constant GOVERNANCE_ROLE = keccak256("GOVERNANCE_ROLE");

    // Provider registry config
    uint256 public providerDepositAmount;

    // Job escrow config
    uint256 public minJobDeposit;
    uint256 public jobRefundFeeBps; // Basis points (100 = 1%)

    // Reward thresholds
    uint256 public epochRewardThreshold; // Minimum reward to trigger auto-claim per epoch
    uint256 public jobRewardThreshold; // Minimum reward to trigger auto-claim per job

    // Epoch settings
    uint256 public epochDuration; // Duration of one epoch in seconds (e.g., 5-10 minutes)

    // Gas bank config
    uint256 public gasBankDailyLimit;

    event ProviderDepositAmountUpdated(uint256 oldAmount, uint256 newAmount);
    event MinJobDepositUpdated(uint256 oldAmount, uint256 newAmount);
    event JobRefundFeeBpsUpdated(uint256 oldBps, uint256 newBps);
    event EpochRewardThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);
    event JobRewardThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);
    event EpochDurationUpdated(uint256 oldDuration, uint256 newDuration);
    event GasBankDailyLimitUpdated(uint256 oldLimit, uint256 newLimit);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(GOVERNANCE_ROLE, msg.sender);

        // Default values
        providerDepositAmount = 1 ether; // 1 ETH deposit for providers
        minJobDeposit = 0.01 ether; // Minimum 0.01 ETH for job deposit
        jobRefundFeeBps = 50; // 0.5% fee on refunds
        epochRewardThreshold = 100 * 10**18; // 100 CLD minimum for auto-claim
        jobRewardThreshold = 10 * 10**18; // 10 CLD minimum for auto-claim
        epochDuration = 300; // 5 minutes default
        gasBankDailyLimit = 10 ether; // 10 ETH per day limit
    }

    function setProviderDepositAmount(uint256 _amount) external onlyRole(GOVERNANCE_ROLE) {
        uint256 oldAmount = providerDepositAmount;
        providerDepositAmount = _amount;
        emit ProviderDepositAmountUpdated(oldAmount, _amount);
    }

    function setMinJobDeposit(uint256 _amount) external onlyRole(GOVERNANCE_ROLE) {
        uint256 oldAmount = minJobDeposit;
        minJobDeposit = _amount;
        emit MinJobDepositUpdated(oldAmount, _amount);
    }

    function setJobRefundFeeBps(uint256 _bps) external onlyRole(GOVERNANCE_ROLE) {
        require(_bps <= 10000, "Config: BPS cannot exceed 10000");
        uint256 oldBps = jobRefundFeeBps;
        jobRefundFeeBps = _bps;
        emit JobRefundFeeBpsUpdated(oldBps, _bps);
    }

    function setEpochRewardThreshold(uint256 _threshold) external onlyRole(GOVERNANCE_ROLE) {
        uint256 oldThreshold = epochRewardThreshold;
        epochRewardThreshold = _threshold;
        emit EpochRewardThresholdUpdated(oldThreshold, _threshold);
    }

    function setJobRewardThreshold(uint256 _threshold) external onlyRole(GOVERNANCE_ROLE) {
        uint256 oldThreshold = jobRewardThreshold;
        jobRewardThreshold = _threshold;
        emit JobRewardThresholdUpdated(oldThreshold, _threshold);
    }

    function setEpochDuration(uint256 _duration) external onlyRole(GOVERNANCE_ROLE) {
        require(_duration > 0, "Config: Duration must be greater than zero");
        uint256 oldDuration = epochDuration;
        epochDuration = _duration;
        emit EpochDurationUpdated(oldDuration, _duration);
    }

    function setGasBankDailyLimit(uint256 _limit) external onlyRole(GOVERNANCE_ROLE) {
        uint256 oldLimit = gasBankDailyLimit;
        gasBankDailyLimit = _limit;
        emit GasBankDailyLimitUpdated(oldLimit, _limit);
    }
}

contracts/EmissionController.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./CLDToken.sol";
import "./Treasury.sol";
import "./MerkleRewardsPoUW.sol";

/**
 * @title EmissionController
 * @dev Controls daily emissions with exponential decay
 * E(t) = E0 * exp(-k * t)
 */
contract EmissionController is AccessControl {
    bytes32 public constant EMITTER_ROLE = keccak256("EMITTER_ROLE");

    CLDToken public immutable token;
    Treasury public immutable treasury;
    MerkleRewardsPoUW public merkleRewards; // Mutable to allow setting after deployment
    address public governanceIncentives; // Address for governance incentives (7%)

    uint256 public startTimestamp;
    uint256 public epochDuration; // Duration of one epoch in seconds
    bool public emissionsStarted;

    // Emission parameters
    uint256 public E0; // Initial daily emission (scaled by 1e18)
    uint256 public k; // Decay constant (scaled by 1e18, e.g., 0.003 = 3e15)

    // Bucket percentages (basis points)
    uint256 public constant VALIDATORS_BPS = 3500; // 35%
    uint256 public constant POUW_BPS = 4000; // 40%
    uint256 public constant TREASURY_BPS = 1800; // 18%
    uint256 public constant GOVERNANCE_BPS = 700; // 7%

    // Epoch tracking
    mapping(uint256 => bool) public epochProcessed;
    mapping(uint256 => uint256) public pouwBudget; // Budget for PoUW per epoch

    event EmissionsStarted(uint256 startTimestamp, uint256 E0, uint256 k);
    event EpochProcessed(uint256 epoch, uint256 totalEmission, uint256 validatorsAmount, uint256 pouwBudget, uint256 treasuryAmount, uint256 governanceAmount);
    event GovernanceIncentivesUpdated(address oldAddress, address newAddress);
    event MerkleRewardsUpdated(address oldAddress, address newAddress);

    constructor(
        address _token,
        address _treasury,
        address _merkleRewards,
        uint256 _epochDuration
    ) {
        require(_token != address(0), "EmissionController: Invalid token");
        require(_treasury != address(0), "EmissionController: Invalid treasury");
        require(_epochDuration > 0, "EmissionController: Invalid epoch duration");

        token = CLDToken(_token);
        treasury = Treasury(payable(_treasury));
        epochDuration = _epochDuration;

        // Allow setting merkleRewards after deployment to resolve circular dependency
        if (_merkleRewards != address(0)) {
            merkleRewards = MerkleRewardsPoUW(_merkleRewards);
        }

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(EMITTER_ROLE, msg.sender);

        // Default decay: k = 0.003 (3e15 in wei)
        k = 3e15;
    }

    /**
     * @dev Start emissions
     * @param _E0 Initial daily emission (in wei)
     */
    function startEmissions(uint256 _E0) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(!emissionsStarted, "EmissionController: Already started");
        require(_E0 > 0, "EmissionController: E0 must be greater than zero");

        E0 = _E0;
        startTimestamp = block.timestamp;
        emissionsStarted = true;

        emit EmissionsStarted(startTimestamp, E0, k);
    }

    /**
     * @dev Set decay constant k
     */
    function setDecayConstant(uint256 _k) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(!emissionsStarted, "EmissionController: Cannot change k after start");
        k = _k;
    }

    /**
     * @dev Set governance incentives address
     */
    function setGovernanceIncentives(address _governanceIncentives) external onlyRole(DEFAULT_ADMIN_ROLE) {
        address oldAddress = governanceIncentives;
        governanceIncentives = _governanceIncentives;
        emit GovernanceIncentivesUpdated(oldAddress, _governanceIncentives);
    }

    /**
     * @dev Set merkle rewards address (can only be set once)
     */
    function setMerkleRewards(address _merkleRewards) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_merkleRewards != address(0), "EmissionController: Invalid merkleRewards");
        require(address(merkleRewards) == address(0), "EmissionController: MerkleRewards already set");

        address oldAddress = address(merkleRewards);
        merkleRewards = MerkleRewardsPoUW(_merkleRewards);
        emit MerkleRewardsUpdated(oldAddress, _merkleRewards);
    }

    /**
     * @dev Get current epoch index
     */
    function getCurrentEpoch() public view returns (uint256) {
        require(emissionsStarted, "EmissionController: Not started");
        return (block.timestamp - startTimestamp) / epochDuration;
    }

    /**
     * @dev Calculate emission for a specific epoch
     * E(t) = E0 * exp(-k * t)
     * where t = epoch (days since start)
     */
    function calculateEmission(uint256 epoch) public view returns (uint256) {
        require(emissionsStarted, "EmissionController: Not started");

        // Convert epoch to days (assuming epochDuration is in seconds)
        uint256 daysSinceStart = (epoch * epochDuration) / 1 days;

        // Calculate exp(-k * t) using approximation
        // For small k*t, we can use: exp(-k*t) ≈ 1 - k*t + (k*t)^2/2 - ...
        // For better precision, we use: exp(-k*t) = (1 - k*t/1e18)^(1e18) for small values
        // Or use a more accurate approximation

        // Simplified: exp(-k * daysSinceStart)
        // Using fixed-point math: result = E0 * (1e18 - k * daysSinceStart) / 1e18
        // For better accuracy, we'll use a Taylor series approximation

        if (daysSinceStart == 0) {
            return E0;
        }

        // More accurate: use exp(-k*t) approximation
        // For k*t << 1: exp(-k*t) ≈ 1 - k*t
        // We scale everything by 1e18
        uint256 kt = (k * daysSinceStart) / 1e18;

        // Prevent underflow
        if (kt >= 1e18) {
            return 0;
        }

        // exp(-k*t) ≈ (1e18 - kt) for small kt
        // For better accuracy, we can use: (1e18 - kt + (kt^2)/2) / 1e18
        uint256 expValue = 1e18 - kt;
        if (kt > 0) {
            uint256 kt2 = (kt * kt) / 1e18;
            expValue = expValue + (kt2 / 2);
        }

        return (E0 * expValue) / 1e18;
    }

    /**
     * @dev Process epoch emissions
     * Mints tokens to validators, treasury, governance
     * Sets PoUW budget (does not mint, mint-on-claim)
     */
    function processEpoch(uint256 epoch) public onlyRole(EMITTER_ROLE) {
        require(emissionsStarted, "EmissionController: Not started");
        require(!epochProcessed[epoch], "EmissionController: Epoch already processed");

        uint256 totalEmission = calculateEmission(epoch);
        require(totalEmission > 0, "EmissionController: Zero emission");

        // Calculate bucket amounts
        uint256 validatorsAmount = (totalEmission * VALIDATORS_BPS) / 10000;
        uint256 pouwAmount = (totalEmission * POUW_BPS) / 10000;
        uint256 treasuryAmount = (totalEmission * TREASURY_BPS) / 10000;
        uint256 governanceAmount = (totalEmission * GOVERNANCE_BPS) / 10000;

        // Set PoUW budget (mint-on-claim)
        pouwBudget[epoch] = pouwAmount;

        // Batch mint to reduce gas costs (saves ~90k gas per epoch)
        address governanceRecipient = governanceIncentives != address(0) 
            ? governanceIncentives 
            : address(treasury);

        address[] memory recipients = new address[](2);
        uint256[] memory amounts = new uint256[](2);

        // Treasury receives validators + treasury amounts
        recipients[0] = address(treasury);
        amounts[0] = validatorsAmount + treasuryAmount;

        // Governance recipient gets governance amount
        recipients[1] = governanceRecipient;
        amounts[1] = governanceAmount;

        token.batchMint(recipients, amounts);

        epochProcessed[epoch] = true;

        emit EpochProcessed(epoch, totalEmission, validatorsAmount, pouwAmount, treasuryAmount, governanceAmount);
    }

    /**
     * @dev Process current epoch
     */
    function processCurrentEpoch() external onlyRole(EMITTER_ROLE) {
        uint256 currentEpoch = getCurrentEpoch();
        processEpoch(currentEpoch);
    }

    /**
     * @dev Get PoUW budget for epoch
     */
    function getPouwBudget(uint256 epoch) external view returns (uint256) {
        return pouwBudget[epoch];
    }

    /**
     * @dev Get epoch info (processed status and budget) in single call
     * Reduces external calls for gas optimization
     * @param epoch Epoch index
     * @return processed Whether epoch has been processed
     * @return budget PoUW budget for the epoch
     */
    function getEpochInfo(uint256 epoch) external view returns (bool processed, uint256 budget) {
        return (epochProcessed[epoch], pouwBudget[epoch]);
    }
}

contracts/GasBank.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./Config.sol";

/**
 * @title GasBank
 * @dev Holds ETH for gas funding of relayed transactions
 * Supports daily limits and relayer whitelist
 */
contract GasBank is AccessControl {
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");
    bytes32 public constant FUNDER_ROLE = keccak256("FUNDER_ROLE");

    Config public immutable config;

    mapping(address => bool) public whitelistedRelayers;
    uint256 public spentToday;
    uint256 public lastResetDay;

    event ETHDeposited(address indexed from, uint256 amount);
    event ETHWithdrawn(address indexed to, uint256 amount, address indexed relayer);
    event RelayerWhitelisted(address indexed relayer, bool whitelisted);
    event DailyLimitReset(uint256 day, uint256 newLimit);

    constructor(address _config) {
        require(_config != address(0), "GasBank: Invalid config address");
        config = Config(_config);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(FUNDER_ROLE, msg.sender);
        _grantRole(RELAYER_ROLE, msg.sender);

        lastResetDay = block.timestamp / 1 days;
    }

    /**
     * @dev Receive ETH
     */
    receive() external payable {
        emit ETHDeposited(msg.sender, msg.value);
    }

    /**
     * @dev Deposit ETH (anyone can deposit)
     */
    function depositETH() external payable {
        emit ETHDeposited(msg.sender, msg.value);
    }

    /**
     * @dev Withdraw ETH to relayer (only whitelisted relayers)
     */
    function withdrawForRelay(address payable to, uint256 amount) external onlyRole(RELAYER_ROLE) {
        require(to != address(0), "GasBank: Invalid recipient");
        require(whitelistedRelayers[to] || hasRole(RELAYER_ROLE, to), "GasBank: Relayer not whitelisted");

        _resetDailyLimitIfNeeded();

        uint256 dailyLimit = config.gasBankDailyLimit();
        require(spentToday + amount <= dailyLimit, "GasBank: Daily limit exceeded");
        require(address(this).balance >= amount, "GasBank: Insufficient balance");

        spentToday += amount;

        (bool success, ) = to.call{value: amount}("");
        require(success, "GasBank: ETH transfer failed");

        emit ETHWithdrawn(to, amount, msg.sender);
    }

    /**
     * @dev Whitelist a relayer (only admin)
     */
    function whitelistRelayer(address relayer, bool whitelisted) external onlyRole(DEFAULT_ADMIN_ROLE) {
        whitelistedRelayers[relayer] = whitelisted;
        emit RelayerWhitelisted(relayer, whitelisted);
    }

    /**
     * @dev Reset daily limit if needed
     */
    function _resetDailyLimitIfNeeded() internal {
        uint256 currentDay = block.timestamp / 1 days;
        if (currentDay > lastResetDay) {
            spentToday = 0;
            lastResetDay = currentDay;
            emit DailyLimitReset(currentDay, config.gasBankDailyLimit());
        }
    }

    /**
     * @dev Get ETH balance
     */
    function getETHBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @dev Get remaining daily limit
     */
    function getRemainingDailyLimit() external view returns (uint256) {
        uint256 currentDay = block.timestamp / 1 days;
        uint256 dailyLimit = config.gasBankDailyLimit(); // Single external call

        if (currentDay > lastResetDay) {
            return dailyLimit;
        }

        return dailyLimit > spentToday ? dailyLimit - spentToday : 0;
    }
}

contracts/JobEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./CLDToken.sol";
import "./Config.sol";
import "./ProviderRegistry.sol";

/**
 * @title JobEscrow
 * @dev Manages user job deposits and provider rewards from escrow
 */
contract JobEscrow is AccessControl, ReentrancyGuard {
    bytes32 public constant VALIDATOR_ROLE = keccak256("VALIDATOR_ROLE");
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");

    CLDToken public immutable token;
    Config public immutable config;
    ProviderRegistry public immutable providerRegistry;

    struct Job {
        address user;              // 20 bytes
        address provider;          // 20 bytes
        uint128 depositAmount;     // 16 bytes (sufficient for most tokens, max ~3.4e38)
        uint128 remainingBalance;  // 16 bytes
        uint64 createdAt;          // 8 bytes (timestamp fits until year 2106)
        bool isActive;             // 1 byte
        bool isCompleted;          // 1 byte
        // Total: 82 bytes = 3 storage slots (was 6 slots, saves ~50% gas on writes)
    }

    mapping(bytes32 => Job) public jobs;
    mapping(address => bytes32[]) public userJobs;
    mapping(address => bytes32[]) public providerJobs;

    // Job ID counter (or use hash of user+provider+timestamp)
    uint256 public jobCounter;

    event JobCreated(
        bytes32 indexed jobId,
        address indexed user,
        address indexed provider,
        uint256 depositAmount
    );
    event JobCompleted(bytes32 indexed jobId, address indexed user, address indexed provider);
    event JobCancelled(bytes32 indexed jobId, address indexed user, address indexed provider);
    event BalanceRefunded(
        bytes32 indexed jobId,
        address indexed user,
        uint256 refundAmount,
        uint256 fee
    );
    event ProviderRewardPaid(
        bytes32 indexed jobId,
        address indexed provider,
        uint256 rewardAmount
    );
    event BalanceDeducted(
        bytes32 indexed jobId,
        uint256 amount,
        uint256 newBalance
    );

    constructor(
        address _token,
        address _config,
        address _providerRegistry
    ) {
        require(_token != address(0), "JobEscrow: Invalid token");
        require(_config != address(0), "JobEscrow: Invalid config");
        require(_providerRegistry != address(0), "JobEscrow: Invalid provider registry");

        token = CLDToken(_token);
        config = Config(_config);
        providerRegistry = ProviderRegistry(_providerRegistry);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(VALIDATOR_ROLE, msg.sender);
        _grantRole(RELAYER_ROLE, msg.sender);
    }

    /**
     * @dev Create a job with CLD deposit
     * @param provider Provider address
     * @param depositAmount Amount of CLD to deposit
     */
    function createJob(address provider, uint256 depositAmount) external nonReentrant {
        require(provider != address(0), "JobEscrow: Invalid provider");
        require(
            providerRegistry.isProviderActive(provider),
            "JobEscrow: Provider not active"
        );
        require(depositAmount >= config.minJobDeposit(), "JobEscrow: Insufficient deposit");

        // Transfer CLD from user
        require(
            token.transferFrom(msg.sender, address(this), depositAmount),
            "JobEscrow: Transfer failed"
        );

        bytes32 jobId = keccak256(
            abi.encodePacked(msg.sender, provider, block.timestamp, jobCounter++)
        );

        jobs[jobId] = Job({
            user: msg.sender,
            provider: provider,
            depositAmount: uint128(depositAmount),
            remainingBalance: uint128(depositAmount),
            createdAt: uint64(block.timestamp),
            isActive: true,
            isCompleted: false
        });

        userJobs[msg.sender].push(jobId);
        providerJobs[provider].push(jobId);

        emit JobCreated(jobId, msg.sender, provider, depositAmount);
    }

    /**
     * @dev Complete job and pay provider reward
     * @param jobId Job ID
     * @param rewardAmount Amount to pay provider (from remaining balance)
     */
    function completeJob(bytes32 jobId, uint256 rewardAmount) external nonReentrant {
        Job storage job = jobs[jobId];
        require(job.isActive, "JobEscrow: Job not active");
        require(job.user == msg.sender || hasRole(VALIDATOR_ROLE, msg.sender), "JobEscrow: Unauthorized");

        // Cache remaining balance to reduce storage reads
        uint128 remaining = job.remainingBalance;
        require(rewardAmount <= remaining, "JobEscrow: Reward exceeds balance");

        // Update job state in one go
        job.isActive = false;
        job.isCompleted = true;
        job.remainingBalance = 0; // Clear balance

        uint256 refundAmount = uint256(remaining) - rewardAmount;

        // Pay provider reward
        if (rewardAmount > 0) {
            require(
                token.transfer(job.provider, rewardAmount),
                "JobEscrow: Provider transfer failed"
            );

            // Track reward in provider registry
            providerRegistry.addReward(job.provider, 0, rewardAmount);

            emit ProviderRewardPaid(jobId, job.provider, rewardAmount);
        }

        // Refund remaining balance to user (with fee)
        if (refundAmount > 0) {
            uint256 fee = (refundAmount * config.jobRefundFeeBps()) / 10000;
            uint256 refundAfterFee = refundAmount - fee;

            require(
                token.transfer(job.user, refundAfterFee),
                "JobEscrow: Refund transfer failed"
            );

            emit BalanceRefunded(jobId, job.user, refundAfterFee, fee);
        }

        emit JobCompleted(jobId, job.user, job.provider);
    }

    /**
     * @dev Cancel job and refund (only validator or user)
     * @param jobId Job ID
     */
    function cancelJob(bytes32 jobId) external nonReentrant {
        Job storage job = jobs[jobId];
        require(job.isActive, "JobEscrow: Job not active");
        require(
            job.user == msg.sender || hasRole(VALIDATOR_ROLE, msg.sender),
            "JobEscrow: Unauthorized"
        );

        job.isActive = false;
        job.isCompleted = false;

        // Refund with fee (cache remaining balance)
        uint128 remaining = job.remainingBalance;
        job.remainingBalance = 0; // Clear balance
        uint256 refundAmount = uint256(remaining);
        if (refundAmount > 0) {
            uint256 fee = (refundAmount * config.jobRefundFeeBps()) / 10000;
            uint256 refundAfterFee = refundAmount - fee;

            require(
                token.transfer(job.user, refundAfterFee),
                "JobEscrow: Refund transfer failed"
            );

            emit BalanceRefunded(jobId, job.user, refundAfterFee, fee);
        }

        emit JobCancelled(jobId, job.user, job.provider);
    }

    /**
     * @dev Deduct balance from job (called by validator/backend when balance insufficient)
     * @param jobId Job ID
     * @param amount Amount to deduct
     */
    function deductBalance(bytes32 jobId, uint256 amount) external onlyRole(VALIDATOR_ROLE) {
        Job storage job = jobs[jobId];
        require(job.isActive, "JobEscrow: Job not active");

        // Cache remaining balance
        uint128 remaining = job.remainingBalance;
        require(amount <= remaining, "JobEscrow: Amount exceeds balance");

        uint128 newBalance = remaining - uint128(amount);
        job.remainingBalance = newBalance;

        emit BalanceDeducted(jobId, amount, newBalance);

        // Auto-cancel if balance too low
        if (newBalance < config.minJobDeposit()) {
            job.isActive = false;
            emit JobCancelled(jobId, job.user, job.provider);
        }
    }

    /**
     * @dev Get job info
     */
    function getJob(bytes32 jobId) external view returns (Job memory) {
        return jobs[jobId];
    }

    /**
     * @dev Get user's jobs
     */
    function getUserJobs(address user) external view returns (bytes32[] memory) {
        return userJobs[user];
    }

    /**
     * @dev Get provider's jobs
     */
    function getProviderJobs(address provider) external view returns (bytes32[] memory) {
        return providerJobs[provider];
    }
}

contracts/MerkleRewardsPoUW.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";
import "./CLDToken.sol";
import "./EmissionController.sol";

/**
 * @title MerkleRewardsPoUW
 * @dev PoUW rewards distribution via Merkle roots
 * Mint-on-claim mechanism for gas efficiency
 * Order-independent: setRoot and processEpoch can be called in any order
 */
contract MerkleRewardsPoUW is AccessControl {
    bytes32 public constant SETTLER_ROLE = keccak256("SETTLER_ROLE");

    CLDToken public immutable token;
    EmissionController public immutable emissionController;

    // Epoch -> Merkle root
    mapping(uint256 => bytes32) public merkleRoots;
    // Epoch -> Total amount in root
    mapping(uint256 => uint256) public rootTotalAmounts;
    // Epoch -> Claimed total
    mapping(uint256 => uint256) public claimedTotal;
    // Epoch -> Provider -> Claimed
    mapping(uint256 => mapping(address => bool)) public claimed;

    event RootPublished(uint256 indexed epoch, bytes32 root, uint256 totalAmount);
    event RewardClaimed(uint256 indexed epoch, address indexed provider, uint256 amount);

    constructor(address _token, address _emissionController) {
        require(_token != address(0), "MerkleRewardsPoUW: Invalid token");
        require(_emissionController != address(0), "MerkleRewardsPoUW: Invalid emission controller");

        token = CLDToken(_token);
        emissionController = EmissionController(_emissionController);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(SETTLER_ROLE, msg.sender);
    }

    /**
     * @dev Publish merkle root for epoch (only settler/validator)
     * Can be called before or after processEpoch - order doesn't matter
     * Validation happens at claim time when both root and epoch processing must be complete
     * @param epoch Epoch index
     * @param root Merkle root
     * @param totalAmount Total amount of rewards in this root
     */
    function setRoot(uint256 epoch, bytes32 root, uint256 totalAmount) external onlyRole(SETTLER_ROLE) {
        require(root != bytes32(0), "MerkleRewardsPoUW: Invalid root");
        require(merkleRoots[epoch] == bytes32(0), "MerkleRewardsPoUW: Root already set");
        require(totalAmount > 0, "MerkleRewardsPoUW: Invalid total amount");

        // Store root - validation happens at claim time
        // This allows setRoot to be called independently of processEpoch
        merkleRoots[epoch] = root;
        rootTotalAmounts[epoch] = totalAmount;

        emit RootPublished(epoch, root, totalAmount);
    }

    /**
     * @dev Claim reward for provider
     * Validates that both root is set AND epoch is processed
     * @param epoch Epoch index
     * @param amount Reward amount
     * @param proof Merkle proof
     */
    function claim(uint256 epoch, uint256 amount, bytes32[] calldata proof) external {
        require(merkleRoots[epoch] != bytes32(0), "MerkleRewardsPoUW: Root not set");
        require(!claimed[epoch][msg.sender], "MerkleRewardsPoUW: Already claimed");
        require(amount > 0, "MerkleRewardsPoUW: Invalid amount");

        // CRITICAL: Both root and epoch processing must be complete
        // Single external call to get both values (saves ~20k gas)
        (bool processed, uint256 budget) = emissionController.getEpochInfo(epoch);
        require(processed, "MerkleRewardsPoUW: Epoch not processed yet");
        require(
            budget > 0 && rootTotalAmounts[epoch] <= budget,
            "MerkleRewardsPoUW: Budget insufficient"
        );

        // Verify merkle proof
        bytes32 leaf = keccak256(abi.encodePacked(msg.sender, amount));
        require(
            MerkleProof.verify(proof, merkleRoots[epoch], leaf),
            "MerkleRewardsPoUW: Invalid proof"
        );

        // Check claim doesn't exceed root total
        require(
            claimedTotal[epoch] + amount <= rootTotalAmounts[epoch],
            "MerkleRewardsPoUW: Claim exceeds root total"
        );

        // Mark as claimed
        claimed[epoch][msg.sender] = true;
        claimedTotal[epoch] += amount;

        // Mint tokens to provider (mint-on-claim)
        token.mint(msg.sender, amount);

        emit RewardClaimed(epoch, msg.sender, amount);
    }

    /**
     * @dev Check if provider has claimed for epoch
     */
    function hasClaimed(uint256 epoch, address provider) external view returns (bool) {
        return claimed[epoch][provider];
    }

    /**
     * @dev Get remaining claimable amount for epoch
     */
    function getRemainingClaimable(uint256 epoch) external view returns (uint256) {
        uint256 total = rootTotalAmounts[epoch];
        uint256 claimedAmount = claimedTotal[epoch];
        return total > claimedAmount ? total - claimedAmount : 0;
    }

    /**
     * @dev Check if root is valid (epoch processed and budget sufficient)
     * Useful for off-chain monitoring to check if claims are ready
     * @param epoch Epoch index
     * @return true if root is set, epoch is processed, and budget is sufficient
     */
    function isRootValid(uint256 epoch) external view returns (bool) {
        if (merkleRoots[epoch] == bytes32(0)) return false;

        // Single external call instead of two
        (bool processed, uint256 budget) = emissionController.getEpochInfo(epoch);
        return processed && budget > 0 && rootTotalAmounts[epoch] <= budget;
    }
}

contracts/MockCapOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./CLDToken.sol";

/**
 * @title MockCapOracle
 * @dev Mock oracle for testnet that allows admin to finalize cap with random value R
 * On mainnet, this would be replaced with a VRF-backed oracle
 */
contract MockCapOracle is AccessControl {
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");

    CLDToken public immutable token;
    uint256 public constant TEMPORARY_CAP = 64_000_000 * 10**18; // 64M CLD
    uint256 public constant BASE_CAP = 21_000_000 * 10**18; // 21M CLD
    uint256 public constant MAX_RANDOM = 43_000_000 * 10**18; // 43M CLD

    bool public capFinalized;
    uint256 public finalCap;

    event CapFinalized(uint256 randomValue, uint256 finalCap);

    constructor(address _token) {
        require(_token != address(0), "MockCapOracle: Invalid token address");
        token = CLDToken(_token);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ORACLE_ROLE, msg.sender);
    }

    /**
     * @dev Finalize cap with random value R (for testnet MVP)
     * @param randomValue R ∈ [0, 43M] in wei
     * Final cap = 21M + R
     */
    function finalizeCap(uint256 randomValue) external onlyRole(ORACLE_ROLE) {
        require(!capFinalized, "MockCapOracle: Cap already finalized");
        require(randomValue <= MAX_RANDOM, "MockCapOracle: Random value exceeds max");

        finalCap = BASE_CAP + randomValue;
        capFinalized = true;

        // Set final cap on token
        token.setFinalCap(finalCap);

        emit CapFinalized(randomValue, finalCap);
    }

    /**
     * @dev Get the final cap (if finalized)
     */
    function getFinalCap() external view returns (uint256) {
        require(capFinalized, "MockCapOracle: Cap not yet finalized");
        return finalCap;
    }
}

contracts/ProviderRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./Config.sol";

/**
 * @title ProviderRegistry
 * @dev Registry for providers with deposit requirement
 */
contract ProviderRegistry is AccessControl, ReentrancyGuard {
    bytes32 public constant VALIDATOR_ROLE = keccak256("VALIDATOR_ROLE");

    Config public immutable config;

    struct Provider {
        address providerAddress;     // 20 bytes
        uint128 depositAmount;       // 16 bytes (sufficient for ETH deposits)
        uint64 registeredAt;         // 8 bytes (timestamp fits until year 2106)
        uint128 autoRewardGasDeposit; // 16 bytes (ETH gas deposit)
        bool isActive;               // 1 byte
        bool autoRewardEnabled;      // 1 byte
        // Total: 62 bytes = 2 storage slots (was 4 slots, saves ~50% gas on writes)
    }

    mapping(address => Provider) public providers;
    address[] public providerList;

    // Provider rewards tracking (off-chain calculated, on-chain claimed)
    mapping(address => uint256) public pendingRewards; // Epoch-based rewards
    mapping(address => uint256) public jobRewards; // Job completion rewards

    event ProviderRegistered(address indexed provider, uint256 depositAmount);
    event ProviderDeposited(address indexed provider, uint256 amount);
    event ProviderWithdrawn(address indexed provider, uint256 amount);
    event ProviderDeactivated(address indexed provider);
    event AutoRewardEnabled(address indexed provider, uint256 gasDeposit);
    event AutoRewardDisabled(address indexed provider);
    event RewardAdded(address indexed provider, uint256 epochReward, uint256 jobReward);
    event RewardClaimed(address indexed provider, uint256 amount);

    constructor(address _config) {
        require(_config != address(0), "ProviderRegistry: Invalid config");
        config = Config(_config);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(VALIDATOR_ROLE, msg.sender);
    }

    /**
     * @dev Register as provider with deposit
     */
    function register() external payable nonReentrant {
        require(!providers[msg.sender].isActive, "ProviderRegistry: Already registered");

        uint256 requiredDeposit = config.providerDepositAmount();
        require(msg.value >= requiredDeposit, "ProviderRegistry: Insufficient deposit");

        providers[msg.sender] = Provider({
            providerAddress: msg.sender,
            depositAmount: uint128(requiredDeposit),
            registeredAt: uint64(block.timestamp),
            autoRewardGasDeposit: 0,
            isActive: true,
            autoRewardEnabled: false
        });

        providerList.push(msg.sender);

        // Refund excess if any
        if (msg.value > requiredDeposit) {
            payable(msg.sender).transfer(msg.value - requiredDeposit);
        }

        emit ProviderRegistered(msg.sender, requiredDeposit);
    }

    /**
     * @dev Enable auto-reward with gas deposit
     */
    function enableAutoReward() external payable nonReentrant {
        require(providers[msg.sender].isActive, "ProviderRegistry: Not registered");
        require(!providers[msg.sender].autoRewardEnabled, "ProviderRegistry: Already enabled");
        require(msg.value > 0, "ProviderRegistry: Gas deposit required");

        Provider storage provider = providers[msg.sender];
        provider.autoRewardEnabled = true;
        provider.autoRewardGasDeposit += uint128(msg.value);

        emit AutoRewardEnabled(msg.sender, msg.value);
    }

    /**
     * @dev Disable auto-reward and withdraw gas deposit
     */
    function disableAutoReward() external nonReentrant {
        require(providers[msg.sender].isActive, "ProviderRegistry: Not registered");
        require(providers[msg.sender].autoRewardEnabled, "ProviderRegistry: Not enabled");

        Provider storage provider = providers[msg.sender];
        uint256 gasDeposit = provider.autoRewardGasDeposit;
        provider.autoRewardEnabled = false;
        provider.autoRewardGasDeposit = 0;

        if (gasDeposit > 0) {
            payable(msg.sender).transfer(gasDeposit);
        }

        emit AutoRewardDisabled(msg.sender);
    }

    /**
     * @dev Add reward to provider (only validator/backend)
     */
    function addReward(
        address provider,
        uint256 epochReward,
        uint256 jobReward
    ) external onlyRole(VALIDATOR_ROLE) {
        require(providers[provider].isActive, "ProviderRegistry: Provider not active");

        if (epochReward > 0) {
            pendingRewards[provider] += epochReward;
        }
        if (jobReward > 0) {
            jobRewards[provider] += jobReward;
        }

        emit RewardAdded(provider, epochReward, jobReward);
    }

    /**
     * @dev Claim rewards (for manual claim)
     * Note: Actual CLD rewards are distributed via MerkleRewardsPoUW
     * This is for tracking purposes
     */
    function claimRewards() external nonReentrant {
        require(providers[msg.sender].isActive, "ProviderRegistry: Not registered");

        uint256 totalReward = pendingRewards[msg.sender] + jobRewards[msg.sender];
        require(totalReward > 0, "ProviderRegistry: No rewards to claim");

        // Reset rewards (actual claiming happens via MerkleRewardsPoUW)
        pendingRewards[msg.sender] = 0;
        jobRewards[msg.sender] = 0;

        emit RewardClaimed(msg.sender, totalReward);
    }

    /**
     * @dev Deactivate provider (only admin)
     */
    function deactivateProvider(address provider) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(providers[provider].isActive, "ProviderRegistry: Not active");
        providers[provider].isActive = false;
        emit ProviderDeactivated(provider);
    }

    /**
     * @dev Get provider info
     */
    function getProvider(address provider) external view returns (Provider memory) {
        return providers[provider];
    }

    /**
     * @dev Get total provider count
     */
    function getProviderCount() external view returns (uint256) {
        return providerList.length;
    }

    /**
     * @dev Check if provider is registered and active
     */
    function isProviderActive(address provider) external view returns (bool) {
        return providers[provider].isActive;
    }

    /**
     * @dev Get total rewards for provider
     */
    function getTotalRewards(address provider) external view returns (uint256) {
        return pendingRewards[provider] + jobRewards[provider];
    }
}

contracts/Treasury.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./CLDToken.sol";

/**
 * @title Treasury
 * @dev Treasury contract that receives emissions and holds ETH for gas funding
 */
contract Treasury is AccessControl {
    bytes32 public constant TREASURY_ROLE = keccak256("TREASURY_ROLE");

    CLDToken public immutable token;

    event ETHDeposited(address indexed from, uint256 amount);
    event ETHWithdrawn(address indexed to, uint256 amount);
    event TokenWithdrawn(address indexed token, address indexed to, uint256 amount);

    constructor(address _token) {
        require(_token != address(0), "Treasury: Invalid token address");
        token = CLDToken(_token);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(TREASURY_ROLE, msg.sender);
    }

    /**
     * @dev Receive ETH
     */
    receive() external payable {
        emit ETHDeposited(msg.sender, msg.value);
    }

    /**
     * @dev Deposit ETH
     */
    function depositETH() external payable {
        emit ETHDeposited(msg.sender, msg.value);
    }

    /**
     * @dev Withdraw ETH (only treasury role)
     */
    function withdrawETH(address payable to, uint256 amount) external onlyRole(TREASURY_ROLE) {
        require(to != address(0), "Treasury: Invalid recipient");
        require(address(this).balance >= amount, "Treasury: Insufficient balance");

        (bool success, ) = to.call{value: amount}("");
        require(success, "Treasury: ETH transfer failed");

        emit ETHWithdrawn(to, amount);
    }

    /**
     * @dev Withdraw tokens (only treasury role)
     */
    function withdrawToken(address tokenAddress, address to, uint256 amount) external onlyRole(TREASURY_ROLE) {
        require(to != address(0), "Treasury: Invalid recipient");
        require(tokenAddress != address(0), "Treasury: Invalid token address");

        IERC20(tokenAddress).transfer(to, amount);

        emit TokenWithdrawn(tokenAddress, to, amount);
    }

    /**
     * @dev Get ETH balance
     */
    function getETHBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @dev Get token balance
     */
    function getTokenBalance() external view returns (uint256) {
        return token.balanceOf(address(this));
    }
}

